module top_module(
  input clk,
  input rst_n,
  input [7:0] a,
  input [7:0] b,
  input [1:0] op,
  output [7:0] result,
  output valid
);reg [8:0] overflow_flag;
  assign result = overflow_flag[7:0];
  assign valid = (overflow_flag[8] == 1'b0);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      overflow_flag <= 9'b0;
    end
    else begin
      case (op)
        2'b00: overflow_flag <= a + b;
        2'b01: overflow_flag <= a - b;
        default: overflow_flag <= 9'b0;
      endcase
    end
  end

endmodule
